package com.example.grpc.filetransfer;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;

import java.io.IOException;
import java.io.FileOutputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.UUID;
import java.util.logging.Logger;

public class FileTransferServer {
    private static final Logger logger = Logger.getLogger(FileTransferServer.class.getName());
    private final int port;
    private final Server server;
    private static final String UPLOAD_DIR = "./uploads"; // Directory to save uploaded files

    public FileTransferServer(int port) throws IOException {
        this.port = port;
        // Ensure upload directory exists
        Files.createDirectories(Paths.get(UPLOAD_DIR));
        this.server = ServerBuilder.forPort(port)
                .addService(new FileTransferServiceGrpcImpl())
                .build();
    }

    public void start() throws IOException {
        server.start();
        logger.info("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            // Use stderr here since the logger may have been reset by its JVM shutdown hook.
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            FileTransferServer.this.stop();
            System.err.println("*** server shut down");
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws Exception {
        FileTransferServer server = new FileTransferServer(50051);
        server.start();
        server.blockUntilShutdown();
    }

    static class FileTransferServiceGrpcImpl extends FileTransferServiceGrpc.FileTransferServiceImplBase {

        @Override
        public StreamObserver<FileTransferRequest> transferFile(StreamObserver<FileTransferResponse> responseObserver) {
            return new StreamObserver<FileTransferRequest>() {
                private String fileName = null;
                private long fileSize = 0;
                private long bytesReceived = 0;
                private FileOutputStream fileOutputStream = null;
                private Path tempFilePath = null;
                private boolean metadataReceived = false;

                @Override
                public void onNext(FileTransferRequest request) {
                    try {
                        if (request.hasMetadata()) {
                            if (metadataReceived) {
                                // Already received metadata, unexpected
                                throw new IllegalStateException("Received metadata more than once for a single transfer.");
                            }
                            FileUploadMetadata metadata = request.getMetadata();
                            fileName = metadata.getFilename();
                            fileSize = metadata.getFilesize();
                            // Create a temporary file with a unique name to avoid conflicts
                            String uniqueFileName = UUID.randomUUID().toString() + "_" + fileName;
                            tempFilePath = Paths.get(UPLOAD_DIR, uniqueFileName);
                            fileOutputStream = new FileOutputStream(tempFilePath.toFile());
                            logger.info("Starting upload for file: " + fileName + " (" + fileSize + " bytes) to " + tempFilePath);
                            metadataReceived = true;
                            // Send initial response acknowledging metadata
                            responseObserver.onNext(FileTransferResponse.newBuilder()
                                    .setFilename(fileName)
                                    .setStatus(FileTransferResponse.TransferStatus.IN_PROGRESS)
                                    .setBytesReceived(0)
                                    .setMessage("Metadata received, ready for data chunks.")
                                    .build());
                        } else if (request.hasChunkData()) {
                            if (!metadataReceived) {
                                throw new IllegalStateException("Received data chunk before metadata.");
                            }
                            byte[] chunk = request.getChunkData().toByteArray();
                            fileOutputStream.write(chunk);
                            bytesReceived += chunk.length;

                            // Periodically send progress updates, or always if you want granular control
                            if (bytesReceived % (1024 * 1024) == 0 || bytesReceived == fileSize) { // Every 1MB or on completion
                                logger.info("Received " + bytesReceived + "/" + fileSize + " bytes for " + fileName);
                                responseObserver.onNext(FileTransferResponse.newBuilder()
                                        .setFilename(fileName)
                                        .setStatus(FileTransferResponse.TransferStatus.IN_PROGRESS)
                                        .setBytesReceived(bytesReceived)
                                        .setMessage("Progress update")
                                        .build());
                            }
                        }
                    } catch (Exception e) {
                        logger.severe("Error during file transfer: " + e.getMessage());
                        responseObserver.onError(io.grpc.Status.INTERNAL
                                .withDescription("Error processing file chunk: " + e.getMessage())
                                .asRuntimeException());
                        // Clean up resources in case of error
                        cleanupResources();
                    }
                }

                @Override
                public void onError(Throwable t) {
                    logger.warning("Error from client: " + t.getMessage());
                    responseObserver.onNext(FileTransferResponse.newBuilder()
                            .setFilename(fileName != null ? fileName : "unknown")
                            .setStatus(FileTransferResponse.TransferStatus.FAILED)
                            .setBytesReceived(bytesReceived)
                            .setMessage("Transfer failed: " + t.getMessage())
                            .build());
                    responseObserver.onCompleted();
                    cleanupResources();
                }

                @Override
                public void onCompleted() {
                    try {
                        if (fileOutputStream != null) {
                            fileOutputStream.close();
                        }

                        if (bytesReceived == fileSize) {
                            logger.info("File " + fileName + " received completely: " + bytesReceived + " bytes.");
                            responseObserver.onNext(FileTransferResponse.newBuilder()
                                    .setFilename(fileName)
                                    .setStatus(FileTransferResponse.TransferStatus.COMPLETED)
                                    .setBytesReceived(bytesReceived)
                                    .setMessage("File transfer completed successfully.")
                                    .build());
                        } else {
                            logger.warning("File " + fileName + " transfer completed but bytes mismatch. Expected: " + fileSize + ", Received: " + bytesReceived);
                            responseObserver.onNext(FileTransferResponse.newBuilder()
                                    .setFilename(fileName)
                                    .setStatus(FileTransferResponse.TransferStatus.FAILED)
                                    .setBytesReceived(bytesReceived)
                                    .setMessage("File transfer completed with byte mismatch. Expected: " + fileSize + ", Received: " + bytesReceived)
                                    .build());
                            // Optionally delete the partially received file
                            Files.deleteIfExists(tempFilePath);
                        }
                    } catch (IOException e) {
                        logger.severe("Error closing file or sending completion: " + e.getMessage());
                        responseObserver.onNext(FileTransferResponse.newBuilder()
                                .setFilename(fileName)
                                .setStatus(FileTransferResponse.TransferStatus.FAILED)
                                .setBytesReceived(bytesReceived)
                                .setMessage("Server error during completion: " + e.getMessage())
                                .build());
                    } finally {
                        responseObserver.onCompleted();
                        cleanupResources();
                    }
                }

                private void cleanupResources() {
                    if (fileOutputStream != null) {
                        try {
                            fileOutputStream.close();
                        } catch (IOException e) {
                            logger.severe("Error closing file output stream during cleanup: " + e.getMessage());
                        }
                    }
                }
            };
        }
    }
}

