package com.example.grpc.filetransfer;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.io.IOException;
import java.io.FileInputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.logging.Logger;

public class FileTransferClient {
    private static final Logger logger = Logger.getLogger(FileTransferClient.class.getName());
    private final ManagedChannel channel;
    private final FileTransferServiceGrpc.FileTransferServiceStub asyncStub;

    public FileTransferClient(String host, int port) {
        this(ManagedChannelBuilder.forAddress(host, port).usePlaintext());
    }

    public FileTransferClient(ManagedChannelBuilder<?> channelBuilder) {
        channel = channelBuilder.build();
        asyncStub = FileTransferServiceGrpc.newStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void uploadFile(String filePathString) throws IOException, InterruptedException {
        Path filePath = Paths.get(filePathString);
        if (!Files.exists(filePath)) {
            logger.severe("File not found: " + filePathString);
            return;
        }

        String fileName = filePath.getFileName().toString();
        long fileSize = Files.size(filePath);
        String fileType = Files.probeContentType(filePath); // May return null

        final CountDownLatch finishLatch = new CountDownLatch(1);

        StreamObserver<FileTransferRequest> requestObserver = asyncStub.transferFile(new StreamObserver<FileTransferResponse>() {
            @Override
            public void onNext(FileTransferResponse response) {
                logger.info("Server response: File=" + response.getFilename() + ", Status=" + response.getStatus() +
                        ", Bytes Received=" + response.getBytesReceived() + ", Message=" + response.getMessage());

                if (response.getStatus() == FileTransferResponse.TransferStatus.COMPLETED ||
                    response.getStatus() == FileTransferResponse.TransferStatus.FAILED) {
                    finishLatch.countDown();
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.warning("Error from server: " + t.getMessage());
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Server completed sending responses.");
                finishLatch.countDown(); // Ensure latch counts down even if server doesn't send final COMPLETED status
            }
        });

        try (FileInputStream fileInputStream = new FileInputStream(filePath.toFile())) {
            // 1. Send file metadata
            FileUploadMetadata metadata = FileUploadMetadata.newBuilder()
                    .setFilename(fileName)
                    .setFilesize(fileSize)
                    .setFileType(fileType != null ? fileType : "application/octet-stream")
                    .build();
            FileTransferRequest initialRequest = FileTransferRequest.newBuilder()
                    .setMetadata(metadata)
                    .build();
            requestObserver.onNext(initialRequest);
            logger.info("Sent file metadata: " + fileName + " (" + fileSize + " bytes)");

            // 2. Send file data in chunks
            byte[] buffer = new byte[1024 * 64]; // 64KB chunk size
            int bytesRead;
            long totalBytesSent = 0;

            while ((bytesRead = fileInputStream.read(buffer)) != -1) {
                if (finishLatch.getCount() == 0) { // Check if server has already indicated completion/failure
                    logger.warning("Transfer stopped prematurely by server response.");
                    break;
                }
                FileTransferRequest chunkRequest = FileTransferRequest.newBuilder()
                        .setChunkData(ByteString.copyFrom(buffer, 0, bytesRead))
                        .build();
                requestObserver.onNext(chunkRequest);
                totalBytesSent += bytesRead;
                // Optional: add a small delay to simulate network latency or avoid overwhelming the server
                // Thread.sleep(1);
            }
            logger.info("All data chunks sent. Total bytes sent: " + totalBytesSent);

        } catch (IOException e) {
            logger.severe("Error reading file or sending chunks: " + e.getMessage());
            requestObserver.onError(e); // Notify server of client-side error
        } finally {
            requestObserver.onCompleted(); // Signal the end of client requests
        }

        // Wait for the server to complete the transfer (or for a timeout)
        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warning("File transfer did not complete in time.");
        }
    }

    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java FileTransferClient <path_to_file_to_upload>");
            return;
        }
        String filePath = args[0];

        FileTransferClient client = new FileTransferClient("localhost", 50051);
        try {
            client.uploadFile(filePath);
        } finally {
            client.shutdown();
        }
    }
}